    # === OHM'S LAW (V=IR) ===
    {"id": "EI001", "section": "Electronics Information", "topic": "Ohm's Law", "question_text": "Ohm's Law states the relationship between voltage (V), current (I), and resistance (R). Which formula correctly expresses this?", "options": ["V = I + R", "V = I × R", "V = I / R", "V = R / I"], "correct_index": 1, "difficulty": 1, "explanation": "Ohm's Law: V = IR (Voltage = Current × Resistance). Rearranged: I = V/R and R = V/I. If voltage increases and resistance stays the same, current increases proportionally.", "test_types": ["ASVAB"]},
    {"id": "EI002", "section": "Electronics Information", "topic": "Ohm's Law", "question_text": "A circuit has a voltage of 12V and a resistance of 4 ohms. What is the current?", "options": ["48 amps", "8 amps", "3 amps", "0.33 amps"], "correct_index": 2, "difficulty": 1, "explanation": "Using I = V/R: I = 12V ÷ 4Ω = 3 amps. Check: V = IR = 3 × 4 = 12V. Current is measured in amperes (amps, A).", "test_types": ["ASVAB"]},
    {"id": "EI003", "section": "Electronics Information", "topic": "Ohm's Law", "question_text": "A 6-ohm resistor carries 2 amps of current. What is the voltage across it?", "options": ["3V", "4V", "8V", "12V"], "correct_index": 3, "difficulty": 1, "explanation": "V = IR = 2A × 6Ω = 12V. Voltage is the 'pressure' pushing current through the resistance.", "test_types": ["ASVAB"]},
    {"id": "EI004", "section": "Electronics Information", "topic": "Ohm's Law", "question_text": "If voltage stays constant and resistance doubles, current will:", "options": ["Double", "Stay the same", "Decrease by half", "Increase by half"], "correct_index": 2, "difficulty": 2, "explanation": "From I = V/R, if R doubles while V is constant, I = V/(2R) — the current is halved. Current and resistance are inversely proportional when voltage is constant.", "test_types": ["ASVAB"]},

    # === POWER (P = IV) ===
