    {"id": "EI006", "section": "Electronics Information", "topic": "Power", "question_text": "A circuit operates at 120V and draws 5 amps. What is the power consumed?", "options": ["24W", "115W", "600W", "125W"], "correct_index": 2, "difficulty": 1, "explanation": "P = V × I = 120V × 5A = 600W (600 watts). This is equivalent to a large home appliance like a microwave.", "test_types": ["ASVAB"]},
    {"id": "EI007", "section": "Electronics Information", "topic": "Power", "question_text": "A 100-ohm resistor carries 2 amps. Using P = I²R, what is the power dissipated?", "options": ["200W", "400W", "50W", "10,000W"], "correct_index": 1, "difficulty": 2, "explanation": "P = I²R = (2)² × 100 = 4 × 100 = 400W. This formula is useful when you know current and resistance but not voltage.", "test_types": ["ASVAB"]},
    {"id": "EI008", "section": "Electronics Information", "topic": "Power", "question_text": "Using P = V²/R, what power is dissipated by a 50-ohm resistor with 10V across it?", "options": ["500W", "5W", "2W", "0.5W"], "correct_index": 2, "difficulty": 2, "explanation": "P = V²/R = (10)²/50 = 100/50 = 2W. This formula is useful when you know voltage and resistance but not current.", "test_types": ["ASVAB"]},

    # === SERIES CIRCUITS ===
