    {"id": "EI014", "section": "Electronics Information", "topic": "Parallel Circuits", "question_text": "Two resistors of 6Ω each are connected in parallel. What is the total resistance?", "options": ["12Ω", "6Ω", "3Ω", "1.5Ω"], "correct_index": 2, "difficulty": 2, "explanation": "For two equal resistors in parallel: R_total = R/2 = 6/2 = 3Ω. Using the formula 1/R_total = 1/6 + 1/6 = 2/6, so R_total = 3Ω. Parallel resistance is always less than the smallest resistor.", "test_types": ["ASVAB"]},
    {"id": "EI015", "section": "Electronics Information", "topic": "Parallel Circuits", "question_text": "Adding more resistors in parallel to a circuit will:", "options": ["Increase total resistance", "Decrease total resistance", "Keep total resistance the same", "Double total resistance"], "correct_index": 1, "difficulty": 2, "explanation": "Adding resistors in parallel provides more paths for current, which decreases total resistance. This is opposite to series circuits where adding resistors increases resistance.", "test_types": ["ASVAB"]},
